import { json } from "@sveltejs/kit";
//#region src/routes/api/visit/+server.ts
var POST = async ({ request, platform }) => {
	let path;
	try {
		({path} = await request.json());
	} catch {
		return json({ error: "invalid JSON" }, { status: 400 });
	}
	if (!path || typeof path !== "string") return json({ error: "path required" }, { status: 400 });
	const kv = platform?.env?.BLOG_ANALYTICS;
	if (!kv) return json({ count: 0 });
	const key = `visits:${path}`;
	const current = parseInt(await kv.get(key) ?? "0", 10);
	await kv.put(key, String(current + 1));
	return json({ count: current + 1 });
};
//#endregion
export { POST };
